// 在同一个组件中添加这种渲染方式


import DataEntityContainer from "./DataEntityContainer";
import IconColorPicker from "./Tools/IconPicker";
import {useEffect, useRef, useState} from "react";
import {COMPONENT_MAP} from "./Tools/Constants";
import {useWebSocket} from "../webSocket/WebSocketProvider";




function DynamicParameterCard({renderConfig,params,setParams,title,subtitle}) {
    const [config, setConfig] = useState(null);
    // const [params, setParams] = useState({});
    const [paramIcons, setParamIcons] = useState({});
    const [paramColors, setParamColors] = useState({});
    const [iconPickerOpen, setIconPickerOpen] = useState(null);
    const [pickerPosition, setPickerPosition] = useState({top: 0, left: 0});
    const buttonRefs = useRef({});
    const {sendMessage,isConnected} = useWebSocket();

    // 解析RenderConfig
    useEffect(() => {
        async function parseConfig() {
            try {


                // 初始化状态
                const initialParams = {};
                const initialIcons = {};
                const initialColors = {};

                renderConfig.components.forEach(comp => {
                    initialParams[comp.id] = comp.defaultValue;
                    initialIcons[comp.id] = comp.icon;
                    initialColors[comp.id] = comp.colorIndex;
                });

                setConfig(renderConfig);
                // setParams(initialParams);
                setParamIcons(initialIcons);
                setParamColors(initialColors);
            } catch (error) {
                console.error('Failed to fetch config:', error);
            }
        }

        parseConfig();
    }, [renderConfig]);


    const handleIconClick = (paramKey) => {
        if (iconPickerOpen === paramKey) {
            setIconPickerOpen(null);
            return;
        }

        const button = buttonRefs.current[paramKey];
        if (button) {
            const rect = button.getBoundingClientRect();
            const viewportWidth = window.innerWidth;
            const pickerWidth = 320;

            let left = rect.left + window.scrollX;
            if (left + pickerWidth > viewportWidth) {
                left = viewportWidth - pickerWidth - 16;
            }

            setPickerPosition({
                top: rect.bottom + window.scrollY + 8,
                left: left
            });
            setIconPickerOpen(paramKey);
        }
    };

    const createIconClickHandler = (paramKey) => {
        return (event) => {
            buttonRefs.current[paramKey] = event.currentTarget;
            handleIconClick(paramKey);
        };
    };

    const renderComponent = (componentConfig) => {
        const Component = COMPONENT_MAP[componentConfig.type];

        if (!Component) {
            console.warn(`Unknown component type: ${componentConfig.type}`);
            return null;
        }

        const commonProps = {
            key: componentConfig.id,
            name: componentConfig.name,
            value: params[componentConfig.id],
            // onChange: (val) => setParams(prev => ({...prev, [componentConfig.id]: val})),
            onChange: (val) => {
                setParams(
                    (prev) => {
                        const new_params = {...prev, [componentConfig.id]: val}
                        const msg = {
                            "type":"paramsUpdate",
                            [componentConfig.id]: val
                        }
                        sendMessage(msg)
                        return new_params
                    }
                )
            },
            iconName: paramIcons[componentConfig.id],
            colorIndex: paramColors[componentConfig.id],
            onIconClick: createIconClickHandler(componentConfig.id)
        };

        // 根据组件类型添加特定属性
        const specificProps = {};
        if (componentConfig.min !== undefined) specificProps.min = componentConfig.min;
        if (componentConfig.max !== undefined) specificProps.max = componentConfig.max;

        return <Component {...commonProps} {...specificProps} />;
    };

    if (!config) {
        return <div>Loading...</div>;
    }

    return (
        <DataEntityContainer theme={params.theme || config.theme} title={title} subtitle={subtitle}>
            {config.components.map(renderComponent)}

            {iconPickerOpen && (
                <IconColorPicker
                    paramKey={iconPickerOpen}
                    currentIcon={paramIcons[iconPickerOpen]}
                    currentColor={paramColors[iconPickerOpen]}
                    onSelectIcon={(icon) => setParamIcons(prev => ({...prev, [iconPickerOpen]: icon}))}
                    onSelectColor={(color) => setParamColors(prev => ({...prev, [iconPickerOpen]: color}))}
                    onClose={() => setIconPickerOpen(null)}
                    position={pickerPosition}
                    buttonRef={buttonRefs.current[iconPickerOpen]}
                />
            )}
        </DataEntityContainer>
    );
}

export default DynamicParameterCard;
